  var mode = (e && e.parameter && e.parameter.mode) ? String(e.parameter.mode) : 'book';

  if (mode === 'cancel') {
    var cancelHtml = _serveHtml('Cancel', {
      token: String((e.parameter && e.parameter.token) || ''),
